import { useState } from "react";
import jsPDF from "jspdf";

function App() {
    const [resumeText, setResumeText] = useState("");
    const [jobDescription, setJobDescription] = useState("");
    const [analysis, setAnalysis] = useState(null);
    const [file, setFile] = useState(null);
    const [fileName, setFileName] = useState("");
    const [loading, setLoading] = useState(false);
    const [uploadMessage, setUploadMessage] = useState("");
    const [darkMode, setDarkMode] = useState(false);

    const analyzeResume = async () => {
        setLoading(true);

        const res = await fetch("http://localhost:5000/analyze", {
            method: "POST",
            headers: {
                "Content-Type": "application/json"
            },
            body: JSON.stringify({ resumeText, jobDescription })
        });

        const data = await res.json();
        setAnalysis(data);
        setLoading(false);
    };

    const uploadResume = async () => {
        if (!file) return;

        const formData = new FormData();
        formData.append("resume", file);

        setLoading(true);

        const res = await fetch("http://localhost:5000/upload", {
            method: "POST",
            body: formData
        });

        const data = await res.json();

        if (data.extractedText) {
            setResumeText(data.extractedText);
        }

        setUploadMessage(data.message);
        setLoading(false);
    };

    const getAiExplanation = () => {
        if (!analysis) return "";

        return `Score ${analysis.score}/100 because ${
            analysis.matchedSkills.length
        } skills matched out of ${
            analysis.requiredKeywords.length
        }. Missing: ${analysis.missingSkills.slice(0, 3).join(", ")}`;
    };

    /* 🔥 FINAL PDF FUNCTION */
    const downloadReport = () => {
        if (!analysis) return;

        const doc = new jsPDF();
        let y = 10;

        const addLine = (text, space = 8) => {
            if (y > 280) {
                doc.addPage();
                y = 10;
            }
            doc.text(text, 10, y);
            y += space;
        };

        doc.setFontSize(16);
        addLine("AI Resume Analyzer Report", 10);

        doc.setFontSize(12);

        addLine(`Role: ${analysis.role || "N/A"}`);
        addLine(`Score: ${analysis.score}/100`);

        addLine("");

        addLine("Required Keywords:");
        if (analysis.requiredKeywords?.length) {
            analysis.requiredKeywords.forEach(k => addLine("- " + k));
        } else {
            addLine("None");
        }

        addLine("");

        addLine("Matched Skills:");
        if (analysis.matchedSkills?.length) {
            analysis.matchedSkills.forEach(k => addLine("- " + k));
        } else {
            addLine("None");
        }

        addLine("");

        addLine("Missing Skills:");
        if (analysis.missingSkills?.length) {
            analysis.missingSkills.forEach(k => addLine("- " + k));
        } else {
            addLine("None");
        }

        addLine("");

        addLine("Suggestions:");
        if (analysis.suggestions?.length) {
            analysis.suggestions.forEach(s => addLine("- " + s));
        } else {
            addLine("None");
        }

        addLine("");

        addLine("Explanation:");
        addLine(getAiExplanation(), 10);

        doc.save("resume-analysis.pdf");
    };

    const theme = darkMode
        ? { bg: "#0f172a", card: "#1e293b", text: "#f1f5f9" }
        : { bg: "#f1f5f9", card: "#ffffff", text: "#111827" };

    return (
        <div style={{ background: theme.bg, minHeight: "100vh", padding: "20px" }}>
            <div style={{
                maxWidth: "900px",
                margin: "auto",
                background: theme.card,
                padding: "20px",
                borderRadius: "10px",
                color: theme.text
            }}>
                <h1>AI Resume Analyzer 🚀</h1>

                <button onClick={() => setDarkMode(!darkMode)}>
                    Toggle Theme
                </button>

                {/* Upload */}
                <h3>Upload Resume</h3>
                <input
                    type="file"
                    onChange={(e) => {
                        setFile(e.target.files[0]);
                        setFileName(e.target.files[0]?.name);
                    }}
                />
                <p>{fileName}</p>

                <button onClick={uploadResume}>
                    {loading ? "Uploading..." : "Upload & Extract"}
                </button>

                <p>{uploadMessage}</p>

                {/* Resume */}
                <h3>Resume</h3>
                <textarea
                    value={resumeText}
                    onChange={(e) => setResumeText(e.target.value)}
                    style={{ width: "100%", height: "120px" }}
                />

                {/* JD */}
                <h3>Job Description</h3>
                <textarea
                    value={jobDescription}
                    onChange={(e) => setJobDescription(e.target.value)}
                    style={{ width: "100%", height: "120px" }}
                />

                <button onClick={analyzeResume}>
                    {loading ? "Analyzing..." : "Analyze"}
                </button>

                {/* RESULT */}
                {analysis && (
                    <div>
                        <h2>Role: {analysis.role}</h2>
                        <h2>Score: {analysis.score}</h2>

                        <h3>Required Skills</h3>
                        {analysis.requiredKeywords.map((s, i) => <span key={i}> {s} </span>)}

                        <h3>Matched Skills</h3>
                        {analysis.matchedSkills.map((s, i) => <span key={i}> {s} </span>)}

                        <h3>Missing Skills</h3>
                        {analysis.missingSkills.map((s, i) => <span key={i}> {s} </span>)}

                        <h3>Suggestions</h3>
                        <ul>
                            {analysis.suggestions.map((s, i) => <li key={i}>{s}</li>)}
                        </ul>

                        <h3>AI Explanation</h3>
                        <p>{getAiExplanation()}</p>

                        <button onClick={downloadReport}>
                            Download PDF Report
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
}

export default App;
